css:
.print-format {
    font-family: Arial, sans-serif;
    padding: 20px;
}
.header {
    text-align: center;
    border-bottom: 2px solid #333;
    padding-bottom: 15px;
    margin-bottom: 20px;
}
.header h1 {
    margin: 0;
    font-size: 24px;
    color: #333;
}
.header h2 {
    margin: 5px 0 0;
    font-size: 18px;
    color: #666;
    font-weight: normal;
}
.info-section {
    margin-bottom: 20px;
}
.info-section table {
    width: 100%;
}
.info-section td {
    padding: 4px 8px;
    vertical-align: top;
}
.info-label {
    font-weight: bold;
    width: 150px;
    color: #555;
}
.items-table {
    width: 100%;
    border-collapse: collapse;
    margin: 15px 0;
}
.items-table th {
    background-color: #f5f5f5;
    border: 1px solid #ddd;
    padding: 10px;
    text-align: left;
    font-weight: bold;
}
.items-table td {
    border: 1px solid #ddd;
    padding: 8px 10px;
}
.items-table .text-right {
    text-align: right;
}
.totals-section {
    margin-top: 20px;
    float: right;
    width: 350px;
}
.totals-section table {
    width: 100%;
}
.totals-section td {
    padding: 6px 10px;
}
.totals-section .total-label {
    font-weight: bold;
    text-align: right;
}
.totals-section .total-value {
    text-align: right;
    width: 150px;
}
.grand-total {
    font-size: 16px;
    font-weight: bold;
    border-top: 2px solid #333;
}

/* Payment Box */
.payment-box {
    margin-top: 30px;
    border: 2px solid #e0e0e0;
    border-radius: 8px;
    padding: 15px 20px;
    background-color: #fafafa;
}
.payment-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
    padding-bottom: 10px;
    border-bottom: 1px solid #e0e0e0;
}
.payment-title {
    font-size: 14px;
    font-weight: bold;
    color: #333;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}
.status-badge {
    display: inline-block;
    padding: 4px 14px;
    border-radius: 20px;
    font-size: 12px;
    font-weight: bold;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}
.status-unpaid {
    background-color: #fdecea;
    color: #c0392b;
    border: 1px solid #e6b0aa;
}
.status-partially-paid {
    background-color: #fef9e7;
    color: #d4ac0d;
    border: 1px solid #f9e79f;
}
.status-paid {
    background-color: #eafaf1;
    color: #27ae60;
    border: 1px solid #a9dfbf;
}
.payment-table {
    width: 100%;
}
.payment-table td {
    padding: 4px 0;
}
.payment-label {
    color: #555;
    width: 60%;
}
.payment-value {
    text-align: right;
    color: #333;
}
.outstanding-row {
    border-top: 1px dashed #ccc;
}
.payment-box .outstanding-row td {
    padding-top: 8px;
    font-size: 15px;
}
